package genxsolution.vms.vmsbackend.maintenance_management.maintenance_record.service;
import genxsolution.vms.vmsbackend.maintenance_management.exception.MaintenanceResourceNotFoundException; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_record.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_record.mapper.MaintenanceRecordMapper; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_record.repository.MaintenanceRecordRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class MaintenanceRecordService { private final MaintenanceRecordRepository repository; private final MaintenanceRecordMapper mapper; public MaintenanceRecordService(MaintenanceRecordRepository repository,MaintenanceRecordMapper mapper){this.repository=repository;this.mapper=mapper;} public List<MaintenanceRecordResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public MaintenanceRecordResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("MaintenanceRecord", String.valueOf(id))); } public MaintenanceRecordResponse create(MaintenanceRecordUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public MaintenanceRecordResponse update(UUID id,MaintenanceRecordUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("MaintenanceRecord", String.valueOf(id))); } public void delete(UUID id){ if(!repository.delete(id)) throw new MaintenanceResourceNotFoundException("MaintenanceRecord", String.valueOf(id)); } }
